export function Controller(
  prefixOrOptions?: string | string[] | ControllerOptions,
): ClassDecorator {
  const defaultPath = '/';

  const [path, host, scopeOptions, versionOptions] = isUndefined(
    prefixOrOptions,
  )
    ? [defaultPath, undefined, undefined, undefined]
    : isString(prefixOrOptions) || Array.isArray(prefixOrOptions)
      ? [prefixOrOptions, undefined, undefined, undefined]
      : [
          prefixOrOptions.path || defaultPath,
          prefixOrOptions.host,
          { scope: prefixOrOptions.scope, durable: prefixOrOptions.durable },
          Array.isArray(prefixOrOptions.version)
            ? Array.from(new Set(prefixOrOptions.version))
            : prefixOrOptions.version,
        ];

  return (target: object) => {
    Reflect.defineMetadata(CONTROLLER_WATERMARK, true, target);
    Reflect.defineMetadata(PATH_METADATA, path, target);
    Reflect.defineMetadata(HOST_METADATA, host, target);
    Reflect.defineMetadata(SCOPE_OPTIONS_METADATA, scopeOptions, target);
    Reflect.defineMetadata(VERSION_METADATA, versionOptions, target);
  };
}

import { Injectable, OnModuleInit } from '@nestjs/common';
import { ModuleRef } from '@nestjs/core';
import { BULL_EXTRA_OPTIONS_TOKEN } from './bull.constants';
import { BullExplorer } from './bull.explorer';
import { BullModuleExtraOptions } from './interfaces';

@Injectable()
export class BullRegistrar implements OnModuleInit {
  constructor(
    private readonly moduleRef: ModuleRef,
    private readonly bullExplorer: BullExplorer,
  ) {}

  onModuleInit() {
    const extraOptions = this.getModuleExtras();

    if (extraOptions?.manualRegistration) {
      return;
    }

    this.register();
  }

  register() {
    return this.bullExplorer.register();
  }

  private getModuleExtras(): BullModuleExtraOptions | null {
    try {
      const extrasToken = BULL_EXTRA_OPTIONS_TOKEN;
      return this.moduleRef.get<BullModuleExtraOptions>(extrasToken, {
        strict: false,
      });
    } catch {
      return null;
    }
  }
}

import { ContextType, ExecutionContext } from '@nestjs/common';
import { ExecutionContextHost } from '@nestjs/core/helpers/execution-context-host';
import { GraphQLArgumentsHost } from './gql-arguments-host';
import { normalizeResolverArgs } from '../utils/normalize-resolver-args';

export type GqlContextType = 'graphql' | ContextType;
export type GraphQLExecutionContext = GqlExecutionContext;

export class GqlExecutionContext
  extends ExecutionContextHost
  implements GraphQLArgumentsHost
{
  static create(context: ExecutionContext): GqlExecutionContext {
    const type = context.getType();
    const gqlContext = new GqlExecutionContext(
      normalizeResolverArgs(context.getArgs()),
      context.getClass(),
      context.getHandler(),
    );
    gqlContext.setType(type);
    return gqlContext;
  }

  getType<TContext extends string = GqlContextType>(): TContext {
    return super.getType();
  }

  getRoot<T = any>(): T {
    return this.getArgByIndex(0);
  }

  getArgs<T = any>(): T {
    return this.getArgByIndex(1);
  }

  getContext<T = any>(): T {
    return this.getArgByIndex(2);
  }

  getInfo<T = any>(): T {
    return this.getArgByIndex(3);
  }
}

export function createMongooseAsyncProviders(
  connectionName?: string,
  modelFactories: AsyncModelFactory[] = [],
): Provider[] {
  return modelFactories.reduce((providers, option) => {
    return [
      ...providers,
      {
        provide: getModelToken(option.name, connectionName),
        useFactory: async (connection: Connection, ...args: unknown[]) => {
          const schema = await option.useFactory(...args);
          const model = connection.model(
            option.name,
            schema,
            option.collection,
          );
          return model;
        },
        inject: [getConnectionToken(connectionName), ...(option.inject || [])],
      },
      ...(option.discriminators || []).map((d) => ({
        provide: getModelToken(d.name, connectionName),
        useFactory: (model: Model<Document>) =>
          model.discriminator(d.name, d.schema, d.value),
        inject: [getModelToken(option.name, connectionName)],
      })),
    ];
  }, [] as Provider[]);
}

private static createAsyncProviders(
  options: TypeOrmModuleAsyncOptions,
): Provider[] {
  if (options.useExisting || options.useFactory) {
    return [this.createAsyncOptionsProvider(options)];
  }
  const useClass = options.useClass as Type<TypeOrmOptionsFactory>;
  return [
    this.createAsyncOptionsProvider(options),
    {
      provide: useClass,
      useClass,
    },
  ];
}

private static createAsyncOptionsProvider(
  options: TypeOrmModuleAsyncOptions,
): Provider {
  if (options.useFactory) {
    return {
      provide: TYPEORM_MODULE_OPTIONS,
      useFactory: options.useFactory,
      inject: options.inject || [],
    };
  }
  // `as Type<TypeOrmOptionsFactory>` is a workaround for microsoft/TypeScript#31603
  const inject = [
    (options.useClass || options.useExisting) as Type<TypeOrmOptionsFactory>,
  ];
  return {
    provide: TYPEORM_MODULE_OPTIONS,
    useFactory: async (optionsFactory: TypeOrmOptionsFactory) =>
      await optionsFactory.createTypeOrmOptions(options.name),
    inject,
  };
}

export function AnyFilesInterceptor(
  localOptions?: MulterOptions,
): Type<NestInterceptor> {
  class MixinInterceptor implements NestInterceptor {
    protected multer: MulterInstance;

    constructor(
      @Optional()
      @Inject(MULTER_MODULE_OPTIONS)
      options: MulterModuleOptions = {},
    ) {
      this.multer = (multer as any)({
        ...options,
        ...localOptions,
      });
    }

    async intercept(
      context: ExecutionContext,
      next: CallHandler,
    ): Promise<Observable<any>> {
      const ctx = context.switchToHttp();

      await new Promise<void>((resolve, reject) =>
        this.multer.any()(ctx.getRequest(), ctx.getResponse(), (err: any) => {
          if (err) {
            const error = transformException(err);
            return reject(error);
          }
          resolve();
        }),
      );
      return next.handle();
    }
  }
  const Interceptor = mixin(MixinInterceptor);
  return Interceptor;
}

