protected async resolvePerContext<TInput = any, TResult = TInput>(
  typeOrToken: Type<TInput> | Abstract<TInput> | string | symbol,
  contextModule: Module,
  contextId: ContextId,
  options?: GetOrResolveOptions,
): Promise<TResult | Array<TResult>> {
  const instanceLinkOrArray = options?.strict
    ? this.instanceLinksHost.get(typeOrToken, {
        moduleId: contextModule.id,
        each: options.each,
      })
    : this.instanceLinksHost.get(typeOrToken, {
        each: options?.each,
      });

  const pluckInstance = async (instanceLink: InstanceLink) => {
    const { wrapperRef, collection } = instanceLink;
    if (wrapperRef.isDependencyTreeStatic() && !wrapperRef.isTransient) {
      return wrapperRef.instance;
    }

    const ctorHost = wrapperRef.instance || { constructor: typeOrToken };
    const instance = await this.injector.loadPerContext(
      ctorHost,
      wrapperRef.host!,
      collection,
      contextId,
      wrapperRef,
    );
    if (!instance) {
      throw new UnknownElementException();
    }
    return instance;
  };

  if (Array.isArray(instanceLinkOrArray)) {
    return Promise.all(
      instanceLinkOrArray.map(instanceLink => pluckInstance(instanceLink)),
    );
  }
  return pluckInstance(instanceLinkOrArray);
}

public async lookupComponent<T = any>(
  providers: Map<Function | string | symbol, InstanceWrapper>,
  moduleRef: Module,
  dependencyContext: InjectorDependencyContext,
  wrapper: InstanceWrapper<T>,
  resolutionContext: ResolutionContext = { contextId: STATIC_CONTEXT },
  keyOrIndex?: symbol | string | number,
): Promise<InstanceWrapper<T>> {
  const token = wrapper.token || wrapper.name;
  const { name } = dependencyContext;
  if (wrapper && token === name) {
    throw new UnknownDependenciesException(
      wrapper.name,
      dependencyContext,
      moduleRef,
      { id: wrapper.id },
    );
  }
  if (name && providers.has(name)) {
    const instanceWrapper = providers.get(name)!;
    this.printFoundInModuleLog(name, moduleRef);
    this.addDependencyMetadata(keyOrIndex!, wrapper, instanceWrapper);
    return instanceWrapper;
  }
  return this.lookupComponentInParentModules(
    dependencyContext,
    moduleRef,
    wrapper,
    resolutionContext,
    keyOrIndex,
  );
}

public isStatic(
  contextId: ContextId,
  inquirer: InstanceWrapper | undefined,
): boolean {
  if (!this.isDependencyTreeStatic() || contextId !== STATIC_CONTEXT) {
    return false;
  }

  // Non-transient provider in static context
  if (!this.isTransient) {
    return true;
  }

  const isInquirerRequestScoped =
    inquirer && !inquirer.isDependencyTreeStatic();
  const isStaticTransient = this.isTransient && !isInquirerRequestScoped;
  const rootInquirer = inquirer?.getRootInquirer();

  // Transient provider inquired by non-transient (e.g., DEFAULT -> TRANSIENT)
  if (isStaticTransient && inquirer && !inquirer.isTransient) {
    return true;
  }

  // Nested transient with non-transient root (e.g., DEFAULT -> TRANSIENT -> TRANSIENT)
  if (isStaticTransient && rootInquirer && !rootInquirer.isTransient) {
    return true;
  }

  // Nested transient during initial instantiation (rootInquirer not yet set)
  if (isStaticTransient && inquirer?.isTransient && !rootInquirer) {
    return true;
  }

  return false;
}

sign(payload: string | Buffer | object, options?: JwtSignOptions): string {
  const signOptions = this.mergeJwtOptions(
    { ...options },
    'signOptions'
  ) as jwt.SignOptions;
  const secret = this.getSecretKey(
    payload,
    options,
    'privateKey',
    JwtSecretRequestType.SIGN
  );

  if (secret instanceof Promise) {
    secret.catch(() => {}); // suppress rejection from async provider
    this.logger.warn(
      'For async version of "secretOrKeyProvider", please use "signAsync".'
    );
    throw new WrongSecretProviderError();
  }

  const allowedSignOptKeys = ['secret', 'privateKey'];
  const signOptKeys = Object.keys(signOptions);
  if (
    typeof payload === 'string' &&
    signOptKeys.some((k) => !allowedSignOptKeys.includes(k))
  ) {
    throw new Error(
      'Payload as string is not allowed with the following sign options: ' +
        signOptKeys.join(', ')
    );
  }

  return jwt.sign(payload, secret, signOptions);
}

constructor(...args: any[]) {
  const callback = async (...params: any[]) => {
    const done = params[params.length - 1];
    try {
      const validateResult = await this.validate(...params);
      if (Array.isArray(validateResult)) {
        done(null, ...validateResult);
      } else {
        done(null, validateResult);
      }
    } catch (err) {
      done(err, null);
    }
  };

  if (callbackArity !== undefined) {
    const validate = new.target?.prototype?.validate;
    const arity =
      callbackArity === true ? validate.length + 1 : callbackArity;
    if (validate) {
      Object.defineProperty(callback, 'length', {
        value: arity
      });
    }
  }
  super(...args, callback);

  const passportInstance = this.getPassportInstance();
  if (name) {
    passportInstance.use(name, this as any);
  } else {
    passportInstance.use(this as any);
  }
}

getPassportInstance() {
  return passport;
}

function addMappedTypesDependencyIfApplies(options: ResourceOptions): Rule {
  return (host: Tree, context: SchematicContext) => {
    try {
      if (options.type === 'graphql-code-first') {
        return;
      }
      if (options.type === 'rest') {
        const nodeDependencyRef = getPackageJsonDependency(
          host,
          '@nestjs/swagger',
        );
        if (nodeDependencyRef) {
          options.isSwaggerInstalled = true;
          return;
        }
      }
      const nodeDependencyRef = getPackageJsonDependency(
        host,
        '@nestjs/mapped-types',
      );
      if (!nodeDependencyRef) {
        addPackageJsonDependency(host, {
          type: NodeDependencyType.Default,
          name: '@nestjs/mapped-types',
          version: '*',
        });
        context.addTask(new NodePackageInstallTask());
      }
    } catch {
      // ignore if "package.json" not found
    }
  };
}

public async registerMiddleware(
  middlewareContainer: MiddlewareContainer,
  applicationRef: any,
) {
  const configs = middlewareContainer.getConfigurations();
  const registerAllConfigs = async (
    moduleKey: string,
    middlewareConfig: MiddlewareConfiguration[],
  ) => {
    for (const config of middlewareConfig) {
      await this.registerMiddlewareConfig(
        middlewareContainer,
        config,
        moduleKey,
        applicationRef,
      );
    }
  };

  const entriesSortedByDistance = [...configs.entries()].sort(
    ([moduleA], [moduleB]) => {
      const moduleARef = this.container.getModuleByKey(moduleA)!;
      const moduleBRef = this.container.getModuleByKey(moduleB)!;
      const isModuleAGlobal = moduleARef.distance === Number.MAX_VALUE;
      const isModuleBGlobal = moduleBRef.distance === Number.MAX_VALUE;
      if (isModuleAGlobal && isModuleBGlobal) {
        return 0;
      }
      if (isModuleAGlobal) {
        return -1;
      }
      if (isModuleBGlobal) {
        return 1;
      }
      return moduleARef.distance - moduleBRef.distance;
    },
  );
  for (const [moduleRef, moduleConfigurations] of entriesSortedByDistance) {
    await registerAllConfigs(moduleRef, [...moduleConfigurations]);
  }
}

private async registerHandler(
  applicationRef: HttpServer,
  routeInfo: RouteInfo,
  proxy: <TRequest, TResponse>(
    req: TRequest,
    res: TResponse,
    next: () => void,
  ) => void,
) {
  const { method } = routeInfo;
  const paths = this.routeInfoPathExtractor.extractPathsFrom(routeInfo);
  const isMethodAll = isRequestMethodAll(method);
  const requestMethod = RequestMethod[method];
  const router = await applicationRef.createMiddlewareFactory(method);
  const middlewareFunction = isMethodAll
    ? proxy
    : <TRequest, TResponse>(
        req: TRequest,
        res: TResponse,
        next: () => void,
      ) => {
        const actualRequestMethod = applicationRef.getRequestMethod?.(req);
        if (
          actualRequestMethod === requestMethod ||
          (actualRequestMethod === RequestMethod[RequestMethod.HEAD] &&
            requestMethod === RequestMethod[RequestMethod.GET])
        ) {
          return proxy(req, res, next);
        }
        return next();
      };
  const pathsToApplyMiddleware = [] as string[];
  paths.some(path => path.match(/^\/?$/))
    ? pathsToApplyMiddleware.push('/')
    : pathsToApplyMiddleware.push(...paths);
  pathsToApplyMiddleware.forEach(path => router(path, middlewareFunction));
}

public extractPathsFrom({ path, method, version }: RouteInfo): string[] {
  const versionPaths = this.extractVersionPathFrom(version);

  if (this.isAWildcard(path)) {
    const entries =
      versionPaths.length > 0
        ? versionPaths
            .map(versionPath => [
              this.prefixPath + versionPath + '$',
              this.prefixPath + versionPath + addLeadingSlash(path),
            ])
            .flat()
        : this.prefixPath
          ? [this.prefixPath + '$', this.prefixPath + addLeadingSlash(path)]
          : [addLeadingSlash(path)];

    return Array.isArray(this.excludedGlobalPrefixRoutes)
      ? [
          ...entries,
          ...this.excludedGlobalPrefixRoutes
            .map(route =>
              Array.isArray(versionPaths) && versionPaths.length > 0
                ? versionPaths.map(v => v + addLeadingSlash(route.path))
                : addLeadingSlash(route.path),
            )
            .flat(),
        ]
      : entries;
  }

  return this.extractNonWildcardPathsFrom({ path, method, version });
}

mapToClass = <T extends Function | Type<any>>(
  middleware: T,
  excludedRoutes: ExcludeRouteMetadata[],
  httpAdapter: HttpServer,
) => {
  if (isMiddlewareClass(middleware)) {
    if (excludedRoutes.length <= 0) {
      return middleware;
    }
    const MiddlewareHost = class extends middleware {
      use(...params: unknown[]) {
        const [req, _, next] = params as [Record<string, any>, any, Function];
        const isExcluded = isMiddlewareRouteExcluded(
          req,
          excludedRoutes,
          httpAdapter,
        );
        if (isExcluded) {
          return next();
        }
        return super.use(...params);
      }
    };
    return assignToken(MiddlewareHost, middleware.name);
  }
  return assignToken(
    class {
      use = (...params: unknown[]) => {
        const [req, _, next] = params as [Record<string, any>, any, Function];
        const isExcluded = isMiddlewareRouteExcluded(
          req,
          excludedRoutes,
          httpAdapter,
        );
        if (isExcluded) {
          return next();
        }
        return (middleware as Function)(...params);
      };
    },
  );
}

public select<T>(
  moduleType: Type<T> | DynamicModule,
  selectOptions?: SelectOptions,
): INestApplicationContext {
  const modulesContainer = this.container.getModules();
  const contextModuleCtor = this.contextModule!.metatype;
  const scope = this.scope.concat(contextModuleCtor);

  const moduleTokenFactory = this.container.getModuleTokenFactory();
  const { type, dynamicMetadata } =
    this.moduleCompiler.extractMetadata(moduleType);
  const token = dynamicMetadata
    ? moduleTokenFactory.createForDynamic(
        type,
        dynamicMetadata,
        moduleType as DynamicModule,
      )
    : moduleTokenFactory.createForStatic(type, moduleType as Type);

  const selectedModule = modulesContainer.get(token);
  if (!selectedModule) {
    throw new UnknownModuleException(type.name);
  }

  const options =
    typeof selectOptions?.abortOnError !== 'undefined'
      ? {
          ...this.appOptions,
          ...selectOptions,
        }
      : this.appOptions;

  return new NestApplicationContext(
    this.container,
    options,
    selectedModule,
    scope,
  );
}

function addGlobalPrefix(): Rule {
  return (tree: Tree) => {
    const mainFilePath = 'src/main.ts';
    const fileRef = tree.get(mainFilePath);
    if (!fileRef) {
      return tree;
    }

    const ts = require('ts-morph');
    const tsProject = new ts.Project({
      manipulationSettings: {
        indentationText: ts.IndentationText.TwoSpaces,
      },
    });
    const tsFile = tsProject.addSourceFileAtPath(mainFilePath);
    const bootstrapFunction = tsFile.getFunction('bootstrap');
    const listenStatement = bootstrapFunction.getStatement(
      (node: { getText: () => string | string[] }) =>
        node.getText().includes('listen'),
    );
    const setPrefixStatement = bootstrapFunction.getStatement(
      (node: { getText: () => string | string[] }) =>
        node.getText().includes('setGlobalPrefix'),
    );
    if (!listenStatement || setPrefixStatement) {
      return tree;
    }
    const listenExprIndex = listenStatement.getChildIndex();
    bootstrapFunction.insertStatements(
      listenExprIndex,
      `app.setGlobalPrefix('api');`,
    );
    tree.overwrite(mainFilePath, tsFile.getFullText() as string);
    return tree;
  };
}

function isNullOrUndefined(value: any): value is null | undefined {
  return value === null || value === undefined;
}

export function main(options: ServiceOptions): Rule {
  options = transform(options);
  return (tree: Tree, context: SchematicContext) => {
    return branchAndMerge(
      chain([
        mergeSourceRoot(options),
        addDeclarationToModule(options),
        mergeWith(generate(options)),
        options.format === true ? formatFiles() : noop(),
      ]),
    )(tree, context);
  };
}

function transform(source: ServiceOptions): ServiceOptions {
  const target: ServiceOptions = Object.assign({}, source);
  target.metadata = 'providers';
  target.type = 'service';

  if (isNullOrUndefined(target.name)) {
    throw new SchematicsException('Option (name) is required.');
  }
  const location: Location = new NameParser().parse(target);
  target.name = normalizeToKebabOrSnakeCase(location.name);
  target.path = normalizeToKebabOrSnakeCase(location.path);
  target.language = target.language !== undefined ? target.language : 'ts';
  target.specFileSuffix = normalizeToKebabOrSnakeCase(
    source.specFileSuffix || 'spec',
  );

  target.path = target.flat
    ? target.path
    : join(target.path as Path, target.name);
  return target;
}

public scanFromPrototype<T extends Injectable, R = any>(
  instance: T,
  prototype: object | null,
  callback: (name: string) => R,
): R[] {
  if (!prototype) {
    return [];
  }

  const visitedNames = new Map<string, boolean>();
  const result: R[] = [];

  do {
    for (const property of Object.getOwnPropertyNames(prototype)) {
      if (visitedNames.has(property)) {
        continue;
      }

      visitedNames.set(property, true);

      // reason: https://github.com/nestjs/nest/pull/10821#issuecomment-1411916533
      const descriptor = Object.getOwnPropertyDescriptor(
        prototype,
        property,
      )!;

      if (
        descriptor.set ||
        descriptor.get ||
        isConstructor(property) ||
        !isFunction(prototype[property])
      ) {
        continue;
      }

      const value = callback(property);

      if (isNil(value)) {
        continue;
      }

      result.push(value);
    }
  } while (
    (prototype = Reflect.getPrototypeOf(prototype)) &&
    prototype !== Object.prototype
  );

  return result;
}

public getAllMethodNames(prototype: object | null): string[] {
  if (!prototype) {
    return [];
  }

  if (this.cachedScannedPrototypes.has(prototype)) {
    return this.cachedScannedPrototypes.get(prototype)!;
  }

  const visitedNames = new Map<string, boolean>();
  const result: string[] = [];

  this.cachedScannedPrototypes.set(prototype, result);

  do {
    for (const property of Object.getOwnPropertyNames(prototype)) {
      if (visitedNames.has(property)) {
        continue;
      }

      visitedNames.set(property, true);

      // reason: https://github.com/nestjs/nest/pull/10821#issuecomment-1411916533
      const descriptor = Object.getOwnPropertyDescriptor(prototype, property);

      if (
        descriptor!.set ||
        descriptor!.get ||
        isConstructor(property) ||
        !isFunction(prototype[property])
      ) {
        continue;
      }

      result.push(property);
    }
  } while (
    (prototype = Reflect.getPrototypeOf(prototype)) &&
    prototype !== Object.prototype
  );

  return result;
}

import {
  BullQueueProcessor,
  BullQueueProcessorCallback,
  BullQueueSeparateProcessor,
} from '../bull.types';
import {
  BullQueueAdvancedProcessor,
  BullQueueAdvancedSeparateProcessor,
} from '../interfaces/bull-processor.interfaces';
import { URL } from 'url';

export function isProcessorCallback(
  processor: BullQueueProcessor,
): processor is BullQueueProcessorCallback {
  return 'function' === typeof processor;
}

export function isAdvancedProcessor(
  processor: BullQueueProcessor,
): processor is BullQueueAdvancedProcessor {
  return (
    'object' === typeof processor &&
    !!(processor as BullQueueAdvancedProcessor).callback &&
    isProcessorCallback((processor as BullQueueAdvancedProcessor).callback)
  );
}

export function isSeparateProcessor(
  processor: BullQueueProcessor,
): processor is BullQueueSeparateProcessor {
  return 'string' === typeof processor || processor instanceof URL;
}

export function isAdvancedSeparateProcessor(
  processor: BullQueueProcessor,
): processor is BullQueueAdvancedSeparateProcessor {
  return (
    'object' === typeof processor &&
    !!(processor as BullQueueAdvancedSeparateProcessor).path &&
    isSeparateProcessor((processor as BullQueueAdvancedSeparateProcessor).path)
  );
}

private static inspectRef(
  optionsOrType: mongoose.SchemaTypeOptions<unknown> | Function,
) {
  if (!optionsOrType || typeof optionsOrType !== 'object') {
    return;
  }
  if (typeof optionsOrType?.ref === 'function') {
    try {
      const result = (optionsOrType.ref as Function)();
      if (typeof result?.name === 'string') {
        optionsOrType.ref = result.name;
      }
      optionsOrType.ref = optionsOrType.ref;
    } catch (err) {
      if (err instanceof TypeError) {
        const refClassName = (optionsOrType.ref as Function)?.name;
        throw new Error(
          `Unsupported syntax: Class constructor "${refClassName}" cannot be invoked without 'new'. Make sure to wrap your class reference in an arrow function (for example, "ref: () => ${refClassName}").`,
        );
      }
      throw err;
    }
  } else if (Array.isArray(optionsOrType.type)) {
    if (optionsOrType.type.length > 0) {
      this.inspectRef(optionsOrType.type[0]);
    }
  }
}

static createForClass(target: Type<unknown>): mongoose.SchemaDefinition {
  if (!target) {
    throw new Error(
      `Target class "${target}" passed in to the "DefinitionsFactory#createForClass()" method is "undefined".`,
    );
  }
  let schemaDefinition: mongoose.SchemaDefinition = {};
  let parent: Function = target;

  while (!isUndefined(parent.prototype)) {
    if (parent === Function.prototype) {
      break;
    }
    const schemaMetadata = TypeMetadataStorage.getSchemaMetadataByTarget(
      parent as Type<unknown>,
    );
    if (!schemaMetadata) {
      parent = Object.getPrototypeOf(parent);
      continue;
    }
    schemaMetadata.properties?.forEach((item) => {
      const options = this.inspectTypeDefinition(item.options as any);
      this.inspectRef(item.options as any);

      schemaDefinition = {
        [item.propertyKey]: options as any,
        ...schemaDefinition,
      };
    });
    parent = Object.getPrototypeOf(parent);
  }

  return schemaDefinition;
}

export async function callAppShutdownHook(
  module: Module,
  signal?: string,
): Promise<any> {
  const providers = module.getNonAliasProviders();
  // Module (class) instance is the first element of the providers array
  // Lifecycle hook has to be called once all classes are properly initialized
  const [_, moduleClassHost] = providers.shift()!;
  const instances = [
    ...module.controllers,
    ...providers,
    ...module.injectables,
    ...module.middlewares,
  ];

  const nonTransientInstances = getNonTransientInstances(instances);
  await Promise.all(callOperator(nonTransientInstances, signal));
  const transientInstances = getTransientInstances(instances);
  await Promise.all(callOperator(transientInstances, signal));

  // Call the instance itself
  const moduleClassInstance = moduleClassHost.instance;
  if (
    moduleClassInstance &&
    hasOnAppShutdownHook(moduleClassInstance) &&
    moduleClassHost.isDependencyTreeStatic()
  ) {
    await moduleClassInstance.onApplicationShutdown(signal);
  }
}
